targets.expr:
sum by (job, label_arcgis_gis_service_name) (
  (
    kube_pod_status_ready{
      pod=~"$pod",
      condition="true"
    } == bool 0
  )
  * on (pod, namespace)
    group_left(label_arcgis_gis_service_name)
    kube_pod_labels{
      namespace="arcgis",
      label_arcgis_gis_service_name!=""
    }
)>0

topk(
  10,
  (
    sum by (job, serviceName, serviceType) (
      rate(
        requests_response_time_seconds_sum{
          job=~"$job",
          folderName=~"$folderName",
          serviceType=~"$serviceType",
          serviceName=~"$serviceName",
          operation=~"^.+$"
        }[5m]
      )
    )
    /
    sum by (job, serviceName, serviceType) (
      rate(
        requests_total{
          job=~"$job",
          folderName=~"$folderName",
          serviceType=~"$serviceType",
          serviceName=~"$serviceName",
          operation=~"$operation",
          operation=~"^.+$"
        }[5m]
      )
    )
  )
)
and
sum by (job, serviceName, serviceType) (
  rate(
    requests_total{
      job=~"$job",
      folderName=~"$folderName",
      serviceType=~"$serviceType",
      serviceName=~"$serviceName",
      operation=~"$operation",
      operation=~"^.+$"
    }[5m]
  )
) > 0

topk(
  10,
  (
    sum by (job, username) (
      rate(
        requests_response_time_seconds_counter_total{
          job=~"$job",
          folderName=~"$folderName",
          username=~"$username",
          operation=~"^.+$"
        }[5m]
      )
    )
    /
    sum by (job, username) (
      rate(
        requests_total{
          job=~"$job",
          folderName=~"$folderName",
          serviceType=~"$serviceType",
          serviceName=~"$serviceName",
          username=~"$username",
          operation=~"$operation",
          operation=~"^.+$"
        }[5m]
      )
    )
  )
)
and
sum by (job, username) (
  rate(
    requests_total{
      job=~"$job",
      folderName=~"$folderName",
      serviceType=~"$serviceType",
      serviceName=~"$serviceName",
      username=~"$username",
      operation=~"$operation",
      operation=~"^.+$"
    }[5m]
  )
) > 0

topk(
  10,
  (
    sum by (job, serviceName, serviceType, username, operation) (
      rate(
        requests_response_time_seconds_counter_total{
          job=~"$job",
          folderName=~"$folderName",
          serviceType=~"$serviceType",
          serviceName=~"$serviceName",
          operation=~"$operation",
          username=~"$username",
          operation=~"^.+$"
        }[5m]
      )
    )
    /
    sum by (job, serviceName, serviceType, username, operation) (
      rate(
        requests_total{
          job=~"$job",
          folderName=~"$folderName",
          serviceType=~"$serviceType",
          serviceName=~"$serviceName",
          operation=~"$operation",
          username=~"$username",
          operation=~"^.+$"
        }[5m]
      )
    )
  )
)
and
sum by (job, serviceName, serviceType, username, operation) (
  rate(
    requests_total{
      job=~"$job",
      folderName=~"$folderName",
      serviceType=~"$serviceType",
      serviceName=~"$serviceName",
      operation=~"$operation",
      username=~"$username",
      operation=~"^.+$"
    }[5m]
  )
) > 0

sum by (job, pod, namespace, node, label_arcgis_gis_service_name) (
  (
    rate(
      container_cpu_usage_seconds_total{
        container="main-container",
        pod=~"$pod",
        node=~"$nodeName"
      }[1m]
    )
  )
  * on (pod, namespace)
    group_left(label_arcgis_gis_service_name)
    kube_pod_labels{
      namespace="arcgis",
      label_arcgis_gis_service_name!=""
    }
)
> 0

sum by (pod, namespace, node, label_arcgis_gis_service_name) (
  container_memory_working_set_bytes{
    namespace="arcgis",
    container="main-container"
  }
  * on (pod, namespace)
    group_left(label_arcgis_gis_service_name)
    kube_pod_labels{
      namespace="arcgis",
      label_arcgis_gis_service_name!=""
    }
)

  sum by (label_arcgis_gis_service_name) (
  rate(container_cpu_usage_seconds_total{
    namespace="arcgis",
    container="main-container",
    cpu="total"
  }[1m])
  *
  on(pod)
  group_left(label_arcgis_gis_service_name)
  kube_pod_labels{
    namespace="arcgis",
    label_arcgis_gis_service_name!=""
  }
)
> 0

sum by (label_arcgis_gis_service_name) (
  container_memory_working_set_bytes{
    namespace="arcgis",
    container="main-container"
  }
  * on (pod, namespace)
    group_left(label_arcgis_gis_service_name)
    kube_pod_labels{
      namespace="arcgis",
      label_arcgis_gis_service_name!=""
    }
)

100 *
(
  1 -
  (
    avg by (job,instance) (
      node_filesystem_free_bytes{
        fstype!~"tmpfs|overlay|squashfs",
        mountpoint!~"/var/lib/docker|/var/lib/kubelet"
      }
    )
    /
    avg by (job,instance) (
      node_filesystem_size_bytes{
        fstype!~"tmpfs|overlay|squashfs",
        mountpoint!~"/var/lib/docker|/var/lib/kubelet"
      }
    )
  )
)
* on (instance)
  group_left (nodename)
  max by (job,instance, nodename) (node_uname_info)

sum by (job,instance, nodename) (
  node_filesystem_size_bytes{
    fstype!~"tmpfs|overlay|squashfs"
  }
  -
  node_filesystem_free_bytes{
    fstype!~"tmpfs|overlay|squashfs"
  }
)
/
1024 / 1024 / 1024
* on (instance)
  group_left (nodename)
  max by (job,instance, nodename) (node_uname_info)

sum by (job, pod, label_arcgis_gis_service_name) (
  rate(
    container_cpu_cfs_throttled_periods_total{
      container!="",
    }[1m]
  )
  * on (pod, namespace)
    group_left (label_arcgis_gis_service_name)
    kube_pod_labels{
      namespace="arcgis",
      label_arcgis_gis_service_name!=""
    }
)

sum by (job, pod, namespace, node, label_arcgis_gis_service_name) (
  (
    rate(
      container_network_transmit_bytes_total{
        node=~"$nodeName",
        pod=~"$pod"
      }[1m]
    )
    / 1024 / 1024
  )
  * on (pod, namespace)
    group_left(label_arcgis_gis_service_name)
    kube_pod_labels{
      namespace="arcgis",
      label_arcgis_gis_service_name!=""
    }
)
> 0

100 *
(
  node_memory_MemAvailable_bytes{node=~"$nodeName"}
  / node_memory_MemTotal_bytes {node=~"$nodeName"}
)
* on (instance)
  group_left (nodename)
  max by (instance, nodename) (node_uname_info)

100 *
(
  avg by (job,instance) (
    node_filesystem_free_bytes{
      fstype!~"tmpfs|overlay|squashfs",
      mountpoint!~"/var/lib/docker|/var/lib/kubelet"
    }
  )
  /
  avg by (job, instance) (
    node_filesystem_size_bytes{
      fstype!~"tmpfs|overlay|squashfs",
      mountpoint!~"/var/lib/docker|/var/lib/kubelet"
    }
  )
)
* on (instance)
  group_left (nodename)
  max by (job, instance, nodename) (node_uname_info)

100 *
max by (job, pod, node, container, label_arcgis_gis_service_name) (
  rate(
    container_cpu_usage_seconds_total{
      container="main-container",
      namespace="arcgis",
      node=~"$nodeName",
    }[1m]
  )
  /
  on (pod, namespace, node, container)
    kube_pod_container_resource_limits{
      resource="cpu",
      namespace="arcgis",
    }
  * on (pod, namespace)
    group_left(label_arcgis_gis_service_name)
    kube_pod_labels{
      label_arcgis_gis_service_name!=""
    }
)
> 0

sum by (job, pod, label_arcgis_gis_service_name) (
  (
    max_over_time(
      kube_pod_container_status_last_terminated_reason{
        namespace="arcgis",
        reason="OOMKilled"
      }[5m:]
    )
    > 0
  )
  * on (pod)
    group_left(label_arcgis_gis_service_name)
    kube_pod_labels{
      namespace="arcgis",
      label_arcgis_gis_service_name!=""
    }
)

sum by (job, pod, label_arcgis_gis_service_name) (
  (
    kube_pod_status_ready{
      condition="true",
      pod=~"$pod"
    } > 0
  )
  * on (pod, namespace)
    group_left(label_arcgis_gis_service_name)
    kube_pod_labels{
      namespace="arcgis",
      label_arcgis_gis_service_name!=""
    }
)

100 *
max by (pod, namespace, node, container, label_arcgis_gis_service_name) (
  rate(
    container_memory_usage_bytes{
      image!="",
      container="main-container",
      namespace="arcgis",
      node=~"$nodeName"
    }[5m]
  )
  /
  on (pod, namespace, node, container)
    kube_pod_container_resource_limits{
      resource="memory",
      container="main-container",
      namespace="arcgis",
      node=~"$nodeName"
    }
  * on (pod, namespace)
    group_left(label_arcgis_gis_service_name)
    kube_pod_labels{
      namespace="arcgis",
      label_arcgis_gis_service_name!=""
    }
)
> 1

sum by (pod, namespace, node, label_arcgis_gis_service_name) (
  sum(
    kube_pod_container_resource_requests{
      namespace="arcgis",
      node=~"$nodeName",
      pod=~"$pod",
      resource="cpu"
    }
  ) by (pod, namespace, node)
  * on (pod, namespace)
    group_left(label_arcgis_gis_service_name)
    kube_pod_labels{
      namespace="arcgis",
      label_arcgis_gis_service_name!=""
    }
)
